module multi_pipe_4bit #(
    parameter size = 4
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    output reg [2*size-1:0] mul_out
);

    wire [size-1:0] a_ext = {size{1'b0}}; 
    wire [size-1:0] b_ext = {size{1'b0}}; 

    reg [size-1:0] p_reg [size-1:0];
    reg [2*size-1:0] sum_reg [size-1:0];

    reg [2*size-1:0] product_reg;

    genvar i;
    generate
        for (i = 0; i < size; i = i + 1) begin : mult_loop
            assign p_reg[i] = (mul_b[i]) ? (a_ext << i) : 'd0; 
        end
    endgenerate

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (int i = 0; i < size; i = i + 1) begin
                sum_reg[i] <= 'd0;
            end
        end
        else begin
            sum_reg[0] <= p_reg[0];
            for (int i = 1; i < size; i = i + 1) begin
                sum_reg[i] <= sum_reg[i-1] + p_reg[i];
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            product_reg <= 'd0;
        end
        else begin
            product_reg <= sum_reg[size-1];
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_out <= 'd0;
        end
        else begin
            mul_out <= product_reg;
        end
    end
endmodule
